mapper.select:
select  from ai_attempt
where status in ('claimed','running') and lease_expire_time < #{now}
order by lease_expire_time asc limit 100

mapper.update:
update ai_attempt set status = 'expired', error_code = 'LEASE_EXPIRED',
    error_message = 'Worker lease expired; task returned to queue', finished_at = #{now}, update_time = #{now}
where id = #{id} and fence_token = #{fenceToken} and status in ('claimed','running')
  and lease_expire_time < #{now}

mapper.select:
select seq, level, message, create_time as createTime from ai_attempt_log
where attempt_id = #{attemptId} and seq > #{afterSeq}
order by seq asc limit #{limit}
